    88  void GrpcHealthCheckerImpl::GrpcActiveHealthCheckSession::onDeferredDelete() {
    89    if (client_) {
    90      // If there is an active request it will get reset, so make sure we ignore the reset.
    91      expect_reset_ = true;
    92      client_->close(Network::ConnectionCloseType::Abort);
