   186  void GrpcHealthCheckerImpl::GrpcActiveHealthCheckSession::onInterval() {
   187    if (!client_) {
   188      Upstream::Host::CreateConnectionData conn =
   189          host_->createHealthCheckConnection(parent_.dispatcher_, parent_.transportSocketOptions(),
   190                                             parent_.transportSocketMatchMetadata().get());
   191      client_ = parent_.createCodecClient(conn);
   192      client_->addConnectionCallbacks(connection_callback_impl_);
   193      client_->setCodecConnectionCallbacks(http_connection_callback_impl_);
   194    }
   195
   196    request_encoder_ = &client_->newStream(*this);
   197    request_encoder_->getStream().addCallbacks(*this);
   198
   199  #if defined(__GNUC__) && !defined(__clang__)
   200  #pragma GCC diagnostic push
   201  #pragma GCC diagnostic ignored "-Wdangling-reference"
   202  #endif
   203    const std::string& authority =
   204        getHostname(host_, parent_.authority_value_, parent_.cluster_.info());
   205  #if defined(__GNUC__) && !defined(__clang__)
   206  #pragma GCC diagnostic pop
   207  #endif
   208    auto headers_message =
   209        Grpc::Common::prepareHeaders(authority, parent_.service_method_.service()->full_name(),
   210                                     parent_.service_method_.name(), absl::nullopt);
   211    headers_message->headers().setReferenceUserAgent(
   212        Http::Headers::get().UserAgentValues.EnvoyHealthChecker);
   213
   214    StreamInfo::StreamInfoImpl stream_info(Http::Protocol::Http2, parent_.dispatcher_.timeSource(),
   215                                           local_connection_info_provider_,
   216                                           StreamInfo::FilterState::LifeSpan::FilterChain);
   217    stream_info.setUpstreamInfo(std::make_shared<StreamInfo::UpstreamInfoImpl>());
   218    stream_info.upstreamInfo()->setUpstreamHost(host_);
   219    parent_.request_headers_parser_->evaluateHeaders(headers_message->headers(), stream_info);
   220
   221    Grpc::Common::toGrpcTimeout(parent_.timeout_, headers_message->headers());
   222
   223    Router::FilterUtility::setUpstreamScheme(
   224        headers_message->headers(),
   225        // Here there is no downstream connection so scheme will be based on
   226        // upstream crypto
   227        false, host_->transportSocketFactory().implementsSecureTransport(), true);
   228
   229    auto status = request_encoder_->encodeHeaders(headers_message->headers(), false);
   230    // Encoding will only fail if required headers are missing.
   231    ASSERT(status.ok());
   232
   233    grpc::health::v1::HealthCheckRequest request;
   234    if (parent_.service_name_.has_value()) {
   235      request.set_service(parent_.service_name_.value());
   236    }
   237
   238    request_encoder_->encodeData(*Grpc::Common::serializeToGrpcFrame(request), true);
   239  }
