   140  std::chrono::milliseconds
   141  HealthCheckerImplBase::intervalWithJitter(uint64_t base_time_ms,
   142                                            std::chrono::milliseconds interval_jitter) const {
   143    const uint64_t jitter_percent_mod = interval_jitter_percent_ * base_time_ms / 100;
   144    if (jitter_percent_mod > 0) {
   145      base_time_ms += random_.random() % jitter_percent_mod;
   146    }
   147
   148    if (interval_jitter.count() > 0) {
   149      base_time_ms += (random_.random() % interval_jitter.count());
   150    }
   151
   152    const uint64_t min_interval = runtime_.snapshot().getInteger("health_check.min_interval", 0);
   153    const uint64_t max_interval = runtime_.snapshot().getInteger(
   154        "health_check.max_interval", std::numeric_limits<uint64_t>::max());
   155
   156    uint64_t final_ms = std::min(base_time_ms, max_interval);
   157    // We force a non-zero final MS, to prevent live lock.
   158    final_ms = std::max(uint64_t(1), std::max(final_ms, min_interval));
   159    return std::chrono::milliseconds(final_ms);
   160  }
