   162  void HealthCheckerImplBase::addHosts(const HostVector& hosts) {
   163    for (const HostSharedPtr& host : hosts) {
   164      if (host->disableActiveHealthCheck()) {
   165        continue;
   166      }
   167      active_sessions_[host] = makeSession(host);
   168      host->setHealthChecker(
   169          HealthCheckHostMonitorPtr{new HealthCheckHostMonitorImpl(shared_from_this(), host)});
   170      active_sessions_[host]->start();
   171    }
   172  }
