   174  void HealthCheckerImplBase::onClusterMemberUpdate(const HostVector& hosts_added,
   175                                                    const HostVector& hosts_removed) {
   176    addHosts(hosts_added);
   177    for (const HostSharedPtr& host : hosts_removed) {
   178      if (host->disableActiveHealthCheck()) {
   179        continue;
   180      }
   181      auto session_iter = active_sessions_.find(host);
   182      ASSERT(active_sessions_.end() != session_iter);
   183      // This deletion can happen inline in response to a host failure, so we deferred delete.
   184      session_iter->second->onDeferredDeleteBase();
   185      dispatcher_.deferredDelete(std::move(session_iter->second));
   186      active_sessions_.erase(session_iter);
   187    }
   188  }
