   197  void HealthCheckerImplBase::HealthCheckHostMonitorImpl::setUnhealthy(UnhealthyType type) {
   198    // This is called cross thread. The cluster/health checker might already be gone.
   199    std::shared_ptr<HealthCheckerImplBase> health_checker = health_checker_.lock();
   200    if (health_checker) {
   201      health_checker->setUnhealthyCrossThread(host_.lock(), type);
   202    }
   203  }
   204
   205  void HealthCheckerImplBase::setUnhealthyCrossThread(const HostSharedPtr& host,
   206                                                      HealthCheckHostMonitor::UnhealthyType type) {
   207    if (type == HealthCheckHostMonitor::UnhealthyType::ImmediateHealthCheckFail) {
   208      host->healthFlagSet(Host::HealthFlag::EXCLUDED_VIA_IMMEDIATE_HC_FAIL);
   209    }
   210
   211    // The threading here is complex. The cluster owns the only strong reference to the health
   212    // checker. It might go away when we post to the main thread from a worker thread. To deal with
   213    // this we use the following sequence of events:
   214    // 1) We capture a weak reference to the health checker and post it from worker thread to main
   215    //    thread.
   216    // 2) On the main thread, we make sure it is still valid (as the cluster may have been destroyed).
   217    // 3) Additionally, the host/session may also be gone by then so we check that also.
   218    std::weak_ptr<HealthCheckerImplBase> weak_this = shared_from_this();
   219    dispatcher_.post([weak_this, host]() -> void {
   220      std::shared_ptr<HealthCheckerImplBase> shared_this = weak_this.lock();
   221      if (shared_this == nullptr) {
   222        return;
   223      }
   224
   225      const auto session = shared_this->active_sessions_.find(host);
   226      if (session == shared_this->active_sessions_.end()) {
   227        return;
   228      }
   229
   230      session->second->setUnhealthy(envoy::data::core::v3::PASSIVE, /*retriable=*/false);
   231    });
   232  }
