   256  HealthCheckerImplBase::ActiveHealthCheckSession::~ActiveHealthCheckSession() {
   257    // Make sure onDeferredDeleteBase() has been called. We should not reference our parent at this
   258    // point since we may have been deferred deleted.
   259    ASSERT(interval_timer_ == nullptr && timeout_timer_ == nullptr);
   260  }
