   262  void HealthCheckerImplBase::ActiveHealthCheckSession::onDeferredDeleteBase() {
   263    HealthState state = HealthState::Unhealthy;
   264    // The session is about to be deferred deleted. Make sure all timers are gone and any
   265    // implementation specific state is destroyed.
   266    interval_timer_.reset();
   267    timeout_timer_.reset();
   268    if (!host_->healthFlagGet(Host::HealthFlag::FAILED_ACTIVE_HC)) {
   269      parent_.decHealthy();
   270      state = HealthState::Healthy;
   271    }
   272    if (host_->healthFlagGet(Host::HealthFlag::DEGRADED_ACTIVE_HC)) {
   273      parent_.decDegraded();
   274    }
   275    onDeferredDelete();
   276
   277    // Run callbacks in case something is waiting for health checks to run which will now never run.
   278    if (first_check_) {
   279      parent_.runCallbacks(host_, HealthTransition::Unchanged, state);
   280    }
   281  }
