   283  void HealthCheckerImplBase::ActiveHealthCheckSession::handleSuccess(bool degraded) {
   284    // If we are healthy, reset the # of unhealthy to zero.
   285    num_unhealthy_ = 0;
   286
   287    HealthTransition changed_state = HealthTransition::Unchanged;
   288
   289    if (host_->healthFlagGet(Host::HealthFlag::FAILED_ACTIVE_HC)) {
   290      // If this is the first time we ever got a check result on this host, we immediately move
   291      // it to healthy. This makes startup faster with a small reduction in overall reliability
   292      // depending on the HC settings.
   293      if (first_check_ || ++num_healthy_ == parent_.healthy_threshold_) {
   294        // If the host moves to healthy, clear active HC timeout, which may be toggled off and on
   295        // while the host is unhealthy.
   296        host_->healthFlagClear(Host::HealthFlag::ACTIVE_HC_TIMEOUT);
   297        // A host that was told to exclude based on immediate failure, but is now passing, should
   298        // no longer be excluded.
   299        host_->healthFlagClear(Host::HealthFlag::EXCLUDED_VIA_IMMEDIATE_HC_FAIL);
   300        host_->healthFlagClear(Host::HealthFlag::FAILED_ACTIVE_HC);
   301        parent_.incHealthy();
   302        changed_state = HealthTransition::Changed;
   303        if (parent_.event_logger_) {
   304          parent_.event_logger_->logAddHealthy(parent_.healthCheckerType(), host_, first_check_);
   305        }
   306      } else {
   307        changed_state = HealthTransition::ChangePending;
   308      }
   309      host_->setLastHcPassTime(time_source_.monotonicTime());
   310    }
   311
   312    if (changed_state != HealthTransition::Changed && parent_.always_log_health_check_success_ &&
   313        parent_.event_logger_) {
   314      parent_.event_logger_->logSuccessfulHealthCheck(parent_.healthCheckerType(), host_);
   315    }
   316
   317    changed_state = clearPendingFlag(changed_state);
   318
   319    if (degraded != host_->healthFlagGet(Host::HealthFlag::DEGRADED_ACTIVE_HC)) {
   320      if (degraded) {
   321        host_->healthFlagSet(Host::HealthFlag::DEGRADED_ACTIVE_HC);
   322        parent_.incDegraded();
   323        if (parent_.event_logger_) {
   324          parent_.event_logger_->logDegraded(parent_.healthCheckerType(), host_);
   325        }
   326      } else {
   327        if (parent_.event_logger_) {
   328          parent_.event_logger_->logNoLongerDegraded(parent_.healthCheckerType(), host_);
   329        }
   330        host_->healthFlagClear(Host::HealthFlag::DEGRADED_ACTIVE_HC);
   331      }
   332
   333      // This check ensures that we honor the decision made about Changed vs ChangePending in the
   334      // above block.
   335      // TODO(snowp): should there be degraded_threshold?
   336      if (changed_state == HealthTransition::Unchanged) {
   337        changed_state = HealthTransition::Changed;
   338      }
   339    }
   340
   341    parent_.stats_.success_.inc();
   342    first_check_ = false;
   343    parent_.runCallbacks(host_, changed_state, HealthState::Healthy);
   344
   345    timeout_timer_->disableTimer();
   346    interval_timer_->enableTimer(parent_.interval(HealthState::Healthy, changed_state));
   347  }
