   357  HealthTransition HealthCheckerImplBase::ActiveHealthCheckSession::setUnhealthy(
   358      envoy::data::core::v3::HealthCheckFailureType type, bool retriable) {
   359    // If we are unhealthy, reset the # of healthy to zero.
   360    num_healthy_ = 0;
   361
   362    HealthTransition changed_state = HealthTransition::Unchanged;
   363    if (!host_->healthFlagGet(Host::HealthFlag::FAILED_ACTIVE_HC)) {
   364      if ((!networkHealthCheckFailureType(type) && !retriable) ||
   365          ++num_unhealthy_ == parent_.unhealthy_threshold_) {
   366        host_->healthFlagSet(Host::HealthFlag::FAILED_ACTIVE_HC);
   367        parent_.decHealthy();
   368        changed_state = HealthTransition::Changed;
   369        if (parent_.event_logger_) {
   370          parent_.event_logger_->logEjectUnhealthy(parent_.healthCheckerType(), host_, type);
   371        }
   372      } else {
   373        changed_state = HealthTransition::ChangePending;
   374      }
   375    }
   376
   377    // In the case of network timeout and if the host is currently failed, set the timeout flag.
   378    // Otherwise clear it. This allows a host to toggle between timeout and failure if it's continuing
   379    // to fail for different reasons.
   380    if (type == envoy::data::core::v3::NETWORK_TIMEOUT &&
   381        host_->healthFlagGet(Host::HealthFlag::FAILED_ACTIVE_HC)) {
   382      host_->healthFlagSet(Host::HealthFlag::ACTIVE_HC_TIMEOUT);
   383    } else {
   384      host_->healthFlagClear(Host::HealthFlag::ACTIVE_HC_TIMEOUT);
   385    }
   386
   387    changed_state = clearPendingFlag(changed_state);
   388
   389    if ((first_check_ || parent_.always_log_health_check_failures_) && parent_.event_logger_) {
   390      parent_.event_logger_->logUnhealthy(parent_.healthCheckerType(), host_, type, first_check_);
   391    }
   392
   393    parent_.stats_.failure_.inc();
   394    if (networkHealthCheckFailureType(type)) {
   395      parent_.stats_.network_failure_.inc();
   396    } else if (type == envoy::data::core::v3::PASSIVE) {
   397      parent_.stats_.passive_failure_.inc();
   398    }
   399
   400    first_check_ = false;
   401    parent_.runCallbacks(host_, changed_state, HealthState::Unhealthy);
   402    return changed_state;
   403  }
   404
   405  void HealthCheckerImplBase::ActiveHealthCheckSession::handleFailure(
   406      envoy::data::core::v3::HealthCheckFailureType type, bool retriable) {
   407    HealthTransition changed_state = setUnhealthy(type, retriable);
   408    // It's possible that the previous call caused this session to be deferred deleted.
   409    if (timeout_timer_ != nullptr) {
   410      timeout_timer_->disableTimer();
   411    }
   412
   413    if (interval_timer_ != nullptr) {
   414      interval_timer_->enableTimer(parent_.interval(HealthState::Unhealthy, changed_state));
   415    }
   416  }
   417
   418  HealthTransition
   419  HealthCheckerImplBase::ActiveHealthCheckSession::clearPendingFlag(HealthTransition changed_state) {
   420    if (host_->healthFlagGet(Host::HealthFlag::PENDING_ACTIVE_HC)) {
   421      host_->healthFlagClear(Host::HealthFlag::PENDING_ACTIVE_HC);
   422      // Even though the health value of the host might have not changed, we set this to Changed so
   423      // that the cluster can update its list of excluded hosts.
   424      return HealthTransition::Changed;
   425    }
   426
   427    return changed_state;
   428  }
