   430  void HealthCheckerImplBase::ActiveHealthCheckSession::onIntervalBase() {
   431    onInterval();
   432    timeout_timer_->enableTimer(parent_.timeout_);
   433    parent_.stats_.attempt_.inc();
   434  }
   435
   436  void HealthCheckerImplBase::ActiveHealthCheckSession::onTimeoutBase() {
   437    onTimeout();
   438    handleFailure(envoy::data::core::v3::NETWORK_TIMEOUT);
   439  }
