   441  void HealthCheckerImplBase::ActiveHealthCheckSession::onInitialInterval() {
   442    if (parent_.initial_jitter_.count() == 0) {
   443      onIntervalBase();
   444    } else {
   445      interval_timer_->enableTimer(
   446          std::chrono::milliseconds(parent_.intervalWithJitter(0, parent_.initial_jitter_)));
   447    }
   448  }
