    32  message HealthCheckResponse {
    33    enum ServingStatus {
    34      UNKNOWN = 0;
    35      SERVING = 1;
    36      NOT_SERVING = 2;
    37      SERVICE_UNKNOWN = 3;  // Used only by the Watch method.
