   169  DefaultHealthCheckService::HealthCheckServiceImpl::~HealthCheckServiceImpl() {
   170    grpc::internal::MutexLock lock(&mu_);
   171    shutdown_ = true;
   172    while (num_watches_ > 0) {
   173      shutdown_condition_.Wait(&mu_);
   174    }
